const m10: Question[] = [
  q({ id: "m10-01", module: "M10", topic: "titratie", skill: "begrip", level: 1, type: "mcq", question: "Wat betekent het equivalentiepunt bij de titratie van een eenwaardig zuur met NaOH?", options: ["De indicator is altijd kleurloos.", "Zuur en hydroxide-ionen hebben precies in de reactieverhouding gereageerd.", "De buret is leeg.", "De oplossing heeft altijd pH 7."], correctAnswer: "Zuur en hydroxide-ionen hebben precies in de reactieverhouding gereageerd.", modelAnswer: "Bij het equivalentiepunt zijn zuur en hydroxide-ionen precies volgens de stoichiometrische verhouding verbruikt. Bij sterk zuur/sterke base is de pH daar vaak ongeveer 7, maar dat is niet de definitie.", explanation: "Het equivalentiepunt gaat over molverhouding, niet over de kleur of de buretstand." }),
  q({ id: "m10-02", module: "M10", topic: "buret", skill: "aflezen", level: 1, type: "steps", question: "Een buret staat eerst op 1,25 mL en na titratie op 19,70 mL. Wat is het verbruik en welke aftrekking gebruik je?", modelAnswer: "Verbruik = eindstand − beginstand = 19,70 − 1,25 = 18,45 mL = 0,01845 L.", steps: ["Lees de beginstand af.", "Lees de eindstand af.", "Bereken eindstand min beginstand.", "Zet het verbruik voor de berekening om naar liter."], rubric: ["eindstand − beginstand gebruikt", "18,45 mL gevonden", "0,01845 L correct genoteerd"] }),
  q({ id: "m10-03", module: "M10", topic: "n = c × V", skill: "rekenen", level: 1, type: "calculation", question: "Bereken hoeveel mol NaOH in 25,00 mL van 0,1000 mol/L NaOH.", correctAnswer: "2,500 × 10⁻³ mol", modelAnswer: "Formule: n = c × V. Invullen: n = 0,1000 mol/L × 0,02500 L = 2,500 × 10⁻³ mol.", steps: ["25,00 mL = 0,02500 L", "n = 0,1000 × 0,02500", "n = 2,500 × 10⁻³ mol"] }),
  q({ id: "m10-04", module: "M10", topic: "indicator", skill: "begrip", level: 1, type: "mcq", question: "Welke taak heeft een indicator bij een titratie?", options: ["De indicator verhoogt de concentratie van de titrant.", "De indicator laat met een kleurverandering zien dat het omslaggebied is bereikt.", "De indicator neutraliseert het zuur.", "De indicator meet de massa van het monster."], correctAnswer: "De indicator laat met een kleurverandering zien dat het omslaggebied is bereikt.", modelAnswer: "Een indicator verandert van kleur in een bepaald pH-traject. Je kiest hem zo dat dat traject rond het equivalentiepunt ligt." }),
  q({ id: "m10-05", module: "M10", topic: "titratie", skill: "eenheden", level: 1, type: "open", question: "Leg uit waarom je in n = c × V het volume altijd in liter invult, ook als de buret in milliliter is gegradueerd.", modelAnswer: "De eenheid van c is mol per liter (mol/L). Alleen als V in liter staat, vallen de liters in mol/L × L weg en blijft mol over. Met mL zou je een factor 1000 fout maken.", rubric: ["eenheid mol/L genoemd", "liter als noodzakelijke volume-eenheid uitgelegd", "factor 1000 genoemd"] }),
  q({ id: "m10-06", module: "M10", topic: "zuur-base", skill: "molverhouding", level: 2, type: "calculation", question: "20,00 mL HCl wordt getitreerd met 16,80 mL 0,1250 mol/L NaOH. Bereken de molariteit van HCl.", correctAnswer: "0,1050 mol/L", modelAnswer: "HCl + OH⁻ → Cl⁻ + H₂O, verhouding 1 : 1. n(OH⁻) = 0,1250 × 0,01680 = 2,100 × 10⁻³ mol. Dus n(HCl) = 2,100 × 10⁻³ mol. c(HCl) = 2,100 × 10⁻³ / 0,02000 = 0,1050 mol/L.", steps: ["V = 0,01680 L", "n(OH⁻) = cV", "1 : 1 toepassen", "c(HCl) = n/V"] }),
  q({ id: "m10-07", module: "M10", topic: "molverhouding", skill: "rekenen", level: 2, type: "calculation", question: "Voor H₂SO₄ + 2 OH⁻ → SO₄²⁻ + 2 H₂O is 15,00 mL 0,2000 mol/L NaOH nodig. Hoeveel mol H₂SO₄ zat in het monster?", correctAnswer: "1,500 × 10⁻³ mol", modelAnswer: "n(OH⁻) = 0,2000 × 0,01500 = 3,000 × 10⁻³ mol. De verhouding H₂SO₄ : OH⁻ is 1 : 2. Daarom n(H₂SO₄) = 3,000 × 10⁻³ / 2 = 1,500 × 10⁻³ mol.", commonMistakes: ["De 1 : 2-verhouding niet gebruiken."] }),
  q({ id: "m10-08", module: "M10", topic: "buret", skill: "praktijk", level: 2, type: "open", question: "De blauwe Schellbachstreep vormt bij de meniscus een pijltje. Leg uit hoe dat je aflezing betrouwbaarder maakt.", modelAnswer: "Door breking van licht in de meniscus loopt de blauwe streep optisch samen tot een scherp punt. Dat punt ligt bij de onderkant van de meniscus en maakt het makkelijker om zonder parallax nauwkeurig af te lezen.", rubric: ["meniscus genoemd", "scherp punt/pijltje genoemd", "nauwkeurig aflezen of parallax uitgelegd"] }),
  q({ id: "m10-09", module: "M10", topic: "titratie", skill: "stappenplan", level: 2, type: "order", question: "Zet de essentiële rekenstappen in de juiste volgorde voor een titratie.", options: ["Bepaal n van de bekende titrant met n = c × V.", "Zet het buretverbruik om naar liter.", "Gebruik de molverhouding uit de reactievergelijking.", "Bereken de gevraagde concentratie of massa."], correctAnswer: "Zet het buretverbruik om naar liter. > Bepaal n van de bekende titrant met n = c × V. > Gebruik de molverhouding uit de reactievergelijking. > Bereken de gevraagde concentratie of massa.", modelAnswer: "Eerst liter, dan n = c × V van de bekende oplossing, dan de stoichiometrie, pas daarna de gevraagde grootheid.", steps: ["liter", "n = c × V", "molverhouding", "gevraagde grootheid"] }),
  q({ id: "m10-10", module: "M10", topic: "titratie", skill: "toepassen", level: 2, type: "mixed", question: "Een leerling stopt zodra fenolftaleïne één seconde heel lichtroze is. Noem de functie van die keuze én waarom hard doorslaan ongewenst is.", modelAnswer: "De zwak blijvende roze kleur is het eindpunt: een praktische benadering van het equivalentiepunt. Bij hard doorslaan is te veel NaOH toegevoegd; het gemeten verbruik wordt te groot en de berekende hoeveelheid zuur dus te hoog.", rubric: ["eindpunt als benadering benoemd", "extra NaOH genoemd", "berekende hoeveelheid zuur te hoog geconcludeerd"] }),
  q({ id: "m10-11", module: "M10", topic: "massa%", skill: "rekenen", level: 3, type: "calculation", question: "Een monster azijn van 25,00 mL heeft massa 25,30 g. Titratie laat zien dat het monster 2,000 × 10⁻² mol CH₃COOH bevat. Bereken hoeveel procent van de massa van het monster uit azijnzuur bestaat. molmassa(CH₃COOH) = 60,05 g/mol.", correctAnswer: "4,75%", modelAnswer: "m(CH₃COOH) = n × molmassa = 2,000 × 10⁻² × 60,05 = 1,201 g. Massa% = 1,201 / 25,30 × 100% = 4,75%.", steps: ["m = n × molmassa", "massa oplossing = 25,30 g", "massa% = 1,201 / 25,30 × 100%"] }),
  q({ id: "m10-12", module: "M10", topic: "zuur-base", skill: "combineren", level: 3, type: "calculation", question: "25,00 mL Ba(OH)₂ wordt getitreerd met 31,40 mL 0,1500 mol/L HCl. Bereken de molariteit van Ba(OH)₂.", correctAnswer: "0,09420 mol/L", modelAnswer: "Ba(OH)₂ + 2 HCl → BaCl₂ + 2 H₂O. n(HCl) = 0,1500 × 0,03140 = 4,710 × 10⁻³ mol. n(Ba(OH)₂) = 4,710 × 10⁻³ / 2 = 2,355 × 10⁻³ mol. c = 2,355 × 10⁻³ / 0,02500 = 0,09420 mol/L." }),
  q({ id: "m10-13", module: "M10", topic: "foutenanalyse", skill: "redeneren", level: 3, type: "open", question: "De pipet waarmee het azijnmonster wordt afgemeten is vooraf gespoeld met demiwater in plaats van met het azijnmonster. De leerling gebruikt toch 25,00 mL als monstervolume in de berekening. Wordt de berekende concentratie azijnzuur te hoog, te laag of niet beïnvloed? Leg uit.", modelAnswer: "Te laag. Achtergebleven water verdunt het werkelijk gepipetteerde monster. Er zit dus minder azijnzuur in de 25,00 mL die wordt getitreerd, terwijl de leerling in de berekening doet alsof dit een onverdund representatief monster is.", rubric: ["te laag geconcludeerd", "verdunning door water genoemd", "minder mol zuur in aliquot uitgelegd"] }),
  q({ id: "m10-14", module: "M10", topic: "equivalentiepunt", skill: "uitleg", level: 3, type: "open", question: "Leg het verschil uit tussen equivalentiepunt en eindpunt bij een titratie. Waarom kies je een indicator met een passend omslagtraject?", modelAnswer: "Het equivalentiepunt is het theoretische stoichiometrische punt waarop de reagentia precies in verhouding hebben gereageerd. Het eindpunt is de waargenomen kleurverandering van de indicator. Een passend omslagtraject zorgt dat het eindpunt zo dicht mogelijk bij het equivalentiepunt ligt.", rubric: ["theoretisch vs. waargenomen onderscheiden", "stoichiometrie genoemd", "indicatortraject aan nabijheid gekoppeld"] }),
  q({ id: "m10-15", module: "M10", topic: "titratie", skill: "toetsrekenen", level: 3, type: "mixed", question: "12,50 mL schoonmaakazijn wordt verdund tot 250,0 mL. Van die oplossing vraagt 25,00 mL precies 22,60 mL 0,1000 mol/L NaOH. Bereken de molariteit van CH₃COOH in de oorspronkelijke azijn.", modelAnswer: "In het aliquot: n(NaOH) = 0,1000 × 0,02260 = 2,260 × 10⁻³ mol. Door 1 : 1 is dat n(CH₃COOH) in 25,00 mL verdunde oplossing. c(verdund) = 2,260 × 10⁻³ / 0,02500 = 0,09040 mol/L. De verdunning is 250,0 / 12,50 = 20,00×. c(oorspronkelijk) = 1,808 mol/L.", steps: ["n = cV", "1 : 1", "c verdund", "verdunningsfactor 20,00", "c oorspronkelijk"] }),
  q({ id: "m10-16", module: "M10", topic: "foutenanalyse", skill: "8+ redeneren", level: 4, type: "mixed", question: "Een leerling vult de buret met NaOH maar spoelt hem niet voor met die NaOH-oplossing; er zit nog demiwater aan de wand. Zij rekent wel met de opgegeven molariteit van NaOH. Voorspel het effect op het buretverbruik én op de berekende molariteit van het zuur.", modelAnswer: "De NaOH in de buret is verdund en heeft dus een lagere werkelijke concentratie. Er is een groter volume nodig om hetzelfde aantal mol OH⁻ toe te voegen. Als de leerling met de te hoge opgegeven concentratie rekent, berekent zij uit dat grote volume te veel mol OH⁻ en dus een te hoge zuurconcentratie.", rubric: ["werkelijke NaOH-concentratie lager", "groter volume nodig", "berekende zuurconcentratie te hoog"] }),
  q({ id: "m10-17", module: "M10", topic: "massa%", skill: "8+ rekenketen", level: 4, type: "calculation", question: "8,00 mL citroensap met dichtheid 1,03 g mL⁻¹ wordt verdund tot 100,0 mL. Een aliquot van 20,00 mL verbruikt 18,75 mL 0,08000 mol/L NaOH. Neem citroenzuur als H₃Cit, dat 3 mol OH⁻ per mol zuur reageert. Bereken hoeveel procent van de massa van het monster uit citroenzuur bestaat; molmassa(H₃Cit) = 192,12 g/mol.", correctAnswer: "5,83%", modelAnswer: "n(OH⁻) aliquot = 0,08000 × 0,01875 = 1,500 × 10⁻³ mol. n(H₃Cit) aliquot = /3 = 5,000 × 10⁻⁴ mol. Hele verdunde oplossing is 100,0/20,00 = 5× zoveel: 2,500 × 10⁻³ mol. m zuur = 2,500 × 10⁻³ × 192,12 = 0,4803 g. Massa sap = 8,00 × 1,03 = 8,24 g. Massa% = 0,4803 / 8,24 × 100% = 5,83%.", explanation: "Let op: de berekende waarde is 5,83%; dat is het rekenkundig correcte resultaat en een uitnodiging om jouw eigen stappen te controleren.", commonMistakes: ["De factor 3 van citroenzuur vergeten.", "Alleen het aliquot gebruiken voor de massa van het oorspronkelijke monster."] }),
  q({ id: "m10-18", module: "M10", topic: "indicator", skill: "8+ vergelijken", level: 4, type: "open", question: "Een zwak zuur wordt getitreerd met een sterke base. Leg uit waarom een indicator die rond pH 7 omslaat minder geschikt kan zijn dan fenolftaleïne, zonder alleen ‘want de docent zegt het’ te schrijven.", modelAnswer: "Bij een zwak zuur met sterke base ligt het equivalentiepunt meestal boven pH 7, doordat de gevormde geconjugeerde base met water reageert. Een indicator moet omslaan in het steile deel rond dat equivalentiepunt. Fenolftaleïne heeft een basisch omslaggebied en past daarom vaak beter dan een indicator rond pH 7.", rubric: ["equivalentiepunt boven 7 genoemd", "conjugaat base/hydrolyse genoemd", "omslaggebied aan steile deel gekoppeld"] }),
  q({ id: "m10-19", module: "M10", topic: "titratie", skill: "onderzoeken", level: 4, type: "open", question: "Ontwerp in woorden een controle waarmee je kunt aantonen dat drie titraties voldoende reproduceerbaar zijn. Noem ook wat je doet met een uitbijter.", modelAnswer: "Ik voer minimaal drie titraties uit onder gelijke omstandigheden en vergelijk de buretverbruiken. Concordante waarden liggen dicht bij elkaar, bijvoorbeeld binnen een vooraf gekozen kleine spreiding. Een duidelijke uitbijter onderzoek ik op een aantoonbare uitvoeringsfout; ik verwijder hem niet alleen omdat hij onhandig is, maar herhaal de meting indien nodig.", rubric: ["minimaal drie herhalingen", "spreiding/concordantie genoemd", "uitbijter kritisch en niet willekeurig behandelen"] }),
  q({ id: "m10-20", module: "M10", topic: "foutenanalyse", skill: "8+ combineren", level: 4, type: "mixed", question: "Bij een blanco titratie blijkt 0,20 mL NaOH nodig om alleen CO₂-opname en indicator-effect te compenseren. De leerling corrigeert een gemeten verbruik van 18,40 mL niet. Leg uit welke richting de fout in de berekende zuurconcentratie heeft en hoe je corrigeert.", modelAnswer: "Zonder blanco-correctie wordt 0,20 mL te veel NaOH toegeschreven aan neutralisatie van het zuur. Daardoor wordt n(NaOH), en bij 1 : 1 ook n(zuur), te hoog berekend. Corrigeer het verbruik: 18,40 − 0,20 = 18,20 mL, daarna pas omzetten naar liter en n = c × V toepassen.", rubric: ["te hoge uitkomst", "0,20 mL aftrekken", "correcte volgorde met liter en n=cV"] }),
  q({ id: "m10-58", module: "M10", topic: "indicator", skill: "BINAS 52A gebruiken", level: 3, type: "mixed", question: "Een zwak zuur wordt met een sterke base getitreerd. Beschrijf hoe je met BINAS 52A een indicator kiest zonder de tabelinhoud over te schrijven.", modelAnswer: "Eindantwoord: ik bepaal eerst waar het equivalentiepunt ongeveer ligt. Bij een zwak zuur met een sterke base ligt dat vaak boven pH 7. Daarna raadpleeg ik in BINAS 52A het omslaggebied van mogelijke indicatoren en kies ik een indicator waarvan dat omslaggebied in het steile pH-deel rond het equivalentiepunt ligt. Het eindpunt is de zichtbare kleurverandering; het equivalentiepunt blijft het stoichiometrische punt.", rubric: ["equivalentiepunt eerst bepaald", "BINAS 52A als indicatoroverzicht gebruikt", "omslaggebied aan steile pH-sprong gekoppeld", "eindpunt/equivalentiepunt onderscheiden"], commonMistakes: ["Alleen een bekende indicator noemen zonder omslaggebied of equivalentiepunt te koppelen."] }),
  q({ id: "m10-59", module: "M10", topic: "titratierekenen", skill: "figuur naar rekenroute", level: 3, type: "mixed", question: "Gebruik de meetgegevensfiguur bij deze vraag. Een leerling ziet beginstand 1,25 mL en eindstand 19,70 mL bij 0,1000 mol/L NaOH. Welke rekenroute hoort vóórdat je de molariteit van het zuur berekent?", modelAnswer: "Eindantwoord: eerst bereken je het verbruik: 19,70 − 1,25 = 18,45 mL. Daarna zet je om naar liter: 0,01845 L. Dan bereken je n(NaOH) = 0,1000 mol/L × 0,01845 L = 1,845 × 10⁻³ mol. Pas daarna gebruik je de molverhouding uit de reactievergelijking om mol zuur te vinden en deel je door het monstervolume.", steps: ["Eindstand - beginstand.", "mL omzetten naar L.", "n titrant = molariteit × volume.", "molverhouding gebruiken.", "gevraagde molariteit berekenen."], rubric: ["18,45 mL verbruik", "0,01845 L", "n(NaOH) correct", "molverhouding pas na mol titrant"], visual: { type: "diagram", component: "QuestionTitrationDataFigure", variant: "buret-readings", alt: "Titratiemeetgegevens met beginstand en eindstand van de buret.", caption: "Gebruik de figuur om het buretverbruik af te lezen; de berekening begint pas daarna.", purpose: "calculation-support" } }),
];

const m9: Question[] = [
  q({ id: "m9-01", module: "M9", topic: "polariteit", skill: "begrip", level: 1, type: "mcq", question: "Waarom is de H–Cl-binding polair?", options: ["H en Cl hebben dezelfde elektronegativiteit.", "Cl trekt de bindende elektronen sterker aan dan H.", "HCl is lineair.", "HCl bevat ionen in een rooster."], correctAnswer: "Cl trekt de bindende elektronen sterker aan dan H.", modelAnswer: "Door verschil in elektronegativiteit verschuift de elektrondichtheid naar Cl. Cl krijgt δ⁻ en H δ⁺." }),
  q({ id: "m9-02", module: "M9", topic: "intermoleculaire krachten", skill: "herkennen", level: 1, type: "mcq", question: "Welke intermoleculaire kracht komt voor tussen alle moleculen, ook apolaire?", options: ["Waterstofbrug", "Ion-ionbinding", "Vanderwaalskracht", "Ion-dipoolinteractie"], correctAnswer: "Vanderwaalskracht", modelAnswer: "Vanderwaalskrachten ontstaan door tijdelijke of geïnduceerde dipolen en komen tussen alle moleculen voor." }),
  q({ id: "m9-03", module: "M9", topic: "moleculaire stoffen", skill: "begrip", level: 1, type: "open", question: "Wat is het verschil tussen een polaire binding en een polair molecuul?", modelAnswer: "Een binding is polair als de elektronen ongelijk verdeeld zijn door verschil in elektronegativiteit. Een molecuul is polair als de vectoren van alle bindingsdipolen samen niet opheffen. Een molecuul kan dus polaire bindingen én toch apolair zijn.", rubric: ["bindingsniveau genoemd", "molecuulvorm/dipolsom genoemd", "opheffen genoemd"] }),
  q({ id: "m9-04", module: "M9", topic: "waterstofbrug", skill: "begrip", level: 1, type: "mcq", question: "Wanneer kan een molecuul als donor deelnemen aan waterstofbrugvorming?", options: ["Als het H aan C gebonden heeft.", "Als het H aan N, O of F gebonden heeft.", "Als het een ionrooster vormt.", "Alleen als het molecuul apolair is."], correctAnswer: "Als het H aan N, O of F gebonden heeft.", modelAnswer: "De sterk polaire N–H, O–H of F–H-binding levert een voldoende δ⁺ waterstof voor een waterstofbrug." }),
  q({ id: "m9-05", module: "M9", topic: "bindingen", skill: "structuur", level: 1, type: "structure", question: "Bekijk de structuurformule. Welke functionele groep bevat dit molecuul en kan het als waterstofbrugdonor optreden?", modelAnswer: "De –OH-groep is een alcoholgroep. Omdat het H direct aan O gebonden is, kan ethanol een waterstofbrug doneren én het vrije elektronenpaar op O kan een waterstofbrug accepteren.", structure: { formula: "CH₃—CH₂—OH", groups: ["alcoholgroep (–OH)"], polar: true, hBond: "both", annotation: "ethanol" } }),
  q({ id: "m9-06", module: "M9", topic: "polariteit", skill: "toepassen", level: 2, type: "open", question: "Leg op molecuulniveau uit waarom CO₂ apolair is, terwijl elke C=O-binding polair is.", modelAnswer: "O trekt in elke C=O-binding de elektronen sterker aan, dus beide bindingen zijn polair. CO₂ is lineair en symmetrisch. De twee even grote bindingsdipolen wijzen tegengesteld en heffen elkaar op; het molecuul heeft geen resulterende dipool.", rubric: ["polair door elektronegativiteit", "lineair en symmetrisch", "dipolen heffen op"] }),
  q({ id: "m9-07", module: "M9", topic: "intermoleculaire krachten", skill: "vergelijken", level: 2, type: "mixed", question: "Welke stof heeft naar verwachting het hoogste kookpunt: CH₄, HCl of CH₃OH? Beargumenteer met intermoleculaire krachten.", modelAnswer: "CH₃OH heeft het hoogste kookpunt. CH₄ heeft alleen zwakke vanderwaalskrachten. HCl heeft daarnaast dipool-dipoolinteracties. Methanol is polair en heeft een O–H-groep, waardoor sterke waterstofbruggen tussen moleculen kunnen ontstaan.", rubric: ["CH₃OH gekozen", "CH₄: vanderwaals", "HCl: dipool-dipool", "methanol: waterstofbruggen"] }),
  q({ id: "m9-08", module: "M9", topic: "hydrofiel", skill: "toepassen", level: 2, type: "structure", question: "De structuurformule is CH₃—(CH₂)₁₅—COO⁻ Na⁺. Leg uit waarom dit molecuul zowel een hydrofiele als hydrofobe kant heeft.", modelAnswer: "De lange koolwaterstofketen is apolair en hydrofoob; hij wisselwerkt vooral via vanderwaalskrachten. De geladen carboxylaatkop en Na⁺ zijn hydrofiel doordat ionen sterke ion-dipoolinteracties met water vormen. Dit is een amfifiel deeltje.", structure: { formula: "CH₃—(CH₂)₁₅—COO⁻  Na⁺", groups: ["lange apolaire alkylketen", "carboxylaation"], polar: true, hBond: "acceptor", annotation: "zeepanion" } }),
  q({ id: "m9-09", module: "M9", topic: "materiaal", skill: "microniveau", level: 2, type: "open", question: "Waarom is een metaal doorgaans elektrisch geleidend, terwijl een moleculaire stof als suiker dat als vaste stof niet is?", modelAnswer: "In een metaal zijn gedelokaliseerde elektronen door het metaalrooster beweeglijk en kunnen lading transporteren. In vaste suiker zitten elektronen vast in covalente bindingen en bestaan geen vrije ionen of vrije elektronen; daarom geleidt suiker niet.", rubric: ["gedelokaliseerde elektronen genoemd", "metaalrooster genoemd", "geen vrije ladingsdragers in suiker"] }),
  q({ id: "m9-10", module: "M9", topic: "dipolen", skill: "toepassen", level: 2, type: "mcq", question: "Welk molecuul is, uitgaande van de bekende geometrie, apolair?", options: ["H₂O (gebogen)", "NH₃ (piramidaal)", "CO₂ (lineair)", "SO₂ (gebogen)"], correctAnswer: "CO₂ (lineair)", modelAnswer: "Door de lineaire, symmetrische vorm heffen de twee C=O-dipolen elkaar op." }),
  q({ id: "m9-11", module: "M9", topic: "ion-dipool", skill: "toetsuitleg", level: 3, type: "open", question: "Leg op microniveau uit waarom NaCl goed oplost in water. Gebruik de begrippen ionrooster, dipool, hydratatie en ion-dipoolinteractie.", modelAnswer: "Water is een dipool: de O-zijde is δ⁻ en de H-zijden δ⁺. Aan het oppervlak van het NaCl-ionrooster richten watermoleculen zich met O naar Na⁺ en met H naar Cl⁻. Deze ion-dipoolinteracties hydrateren de ionen en kunnen de ion-ionaantrekkingen in het rooster overwinnen, zodat losse gehydrateerde ionen ontstaan.", rubric: ["water als dipool", "juiste oriëntatie bij Na⁺ en Cl⁻", "hydratatie", "overwinnen roosterinteracties"] }),
  q({ id: "m9-12", module: "M9", topic: "structuur-eigenschap", skill: "redeneren", level: 3, type: "structure", question: "Vergelijk ethylacetaat (CH₃—COO—CH₂—CH₃) met ethanol. Welke heeft meer kans volledig met water te mengen? Licht toe met functionele groepen en waterstofbruggen.", modelAnswer: "Ethanol mengt beter. Ethanol heeft een –OH-groep die zowel waterstofbruggen kan doneren als accepteren. Ethylacetaat heeft een ester: de O-atomen kunnen accepteren, maar er is geen O–H en dus geen donor. Ook heeft ethylacetaat een groter apolair deel.", structure: { formula: "CH₃—C(=O)—O—CH₂—CH₃", groups: ["esterbinding", "carbonylgroep"], polar: true, hBond: "acceptor", annotation: "ethylacetaat" } }),
  q({ id: "m9-13", module: "M9", topic: "intermoleculaire krachten", skill: "combineren", level: 3, type: "mixed", question: "Een polymeer heeft veel amidegroepen (—CONH—). Verklaar waarom zulke polymeren vaak sterke keten-keten-aantrekking hebben en daardoor relatief hoge treksterkte kunnen bezitten.", modelAnswer: "Een amidegroep is polair door de C=O-binding. De N–H kan waterstofbruggen doneren en de carbonyl-O kan die accepteren. Daardoor ontstaan veel waterstofbruggen en dipoolinteracties tussen polymeerketens. Die ketens schuiven minder gemakkelijk langs elkaar, wat de treksterkte verhoogt.", rubric: ["amidegroep polair", "donor en acceptor correct", "interketeninteracties", "koppeling aan treksterkte"] }),
  q({ id: "m9-14", module: "M9", topic: "materialen", skill: "toetsniveau", level: 3, type: "open", question: "Een composiet bestaat uit koolstofvezels in een polymeermatrix. Leg uit waarom zo’n combinatie mechanisch gunstiger kan zijn dan alleen de matrixpolymeer.", modelAnswer: "De polymeermatrix verdeelt belasting en houdt vezels op positie. Koolstofvezels hebben langs hun richting hoge treksterkte en stijfheid. Bij goede hechting draagt de matrix spanning over op de vezels. Zo combineert het composiet de vormbaarheid/taaiheid van de matrix met de sterkte van de vezels.", rubric: ["rol matrix", "rol vezels", "belastingoverdracht/hechting", "combinatie van eigenschappen"] }),
  q({ id: "m9-15", module: "M9", topic: "bindingen", skill: "volgorde", level: 3, type: "order", question: "Zet voor het verklaren van een kookpunt in de meest bruikbare redeneringsvolgorde.", options: ["Koppel de kracht aan benodigde energie en kookpunt.", "Bepaal of het molecuul polair is vanuit bindingen én vorm.", "Noem de relevante intermoleculaire krachten.", "Controleer of een O–H, N–H of F–H-groep waterstofbruggen mogelijk maakt."], correctAnswer: "Bepaal of het molecuul polair is vanuit bindingen én vorm. > Controleer of een O–H, N–H of F–H-groep waterstofbruggen mogelijk maakt. > Noem de relevante intermoleculaire krachten. > Koppel de kracht aan benodigde energie en kookpunt.", modelAnswer: "Van structuur naar polariteit, dan specifieke H-brugmogelijkheid, dan krachten, dan eigenschap." }),
  q({ id: "m9-16", module: "M9", topic: "polariteit", skill: "8+ redeneren", level: 4, type: "mixed", question: "Een leerling zegt: ‘CCl₄ is polair want elke C–Cl-binding is polair.’ Beoordeel deze uitspraak volledig en voorspel tegelijk welk type intermoleculaire kracht tussen CCl₄-moleculen dominant is.", modelAnswer: "De bindingen zijn inderdaad polair omdat Cl elektronen sterker aantrekt dan C. CCl₄ is echter tetraëdrisch en symmetrisch; de vier bindingsdipolen heffen elkaar op. Het molecuul is dus apolair. Tussen CCl₄-moleculen zijn vanderwaalskrachten dominant, al zijn die door de goed polariseerbare Cl-atomen niet per se heel zwak.", rubric: ["bindingspolariteit erkend", "tetraëdrische symmetrie", "molecuul apolair", "vanderwaals als dominant"] }),
  q({ id: "m9-17", module: "M9", topic: "hydrofiel", skill: "8+ combineren", level: 4, type: "open", question: "Leg uit waarom een fosfolipide in water spontaan een dubbellaag kan vormen. Gebruik hydrofoob, hydrofiel, vanderwaals en waterstofbrug/ion-dipool waar passend.", modelAnswer: "De geladen of polaire fosfaatkoppen zijn hydrofiel en vormen gunstige ion-dipoolinteracties en vaak waterstofbruggen met water. De apolaire vetzuurstaarten zijn hydrofoob; water rond die staarten is ongunstig geordend. Door staarten naar binnen te keren en onderling vanderwaalsinteracties te laten maken, terwijl koppen naar water wijzen, ontstaat een dubbellaag.", rubric: ["koppen hydrofiel", "staarten hydrofoob", "staarten naar binnen", "juiste krachten gekoppeld"] }),
  q({ id: "m9-18", module: "M9", topic: "structuur-eigenschap", skill: "8+ analyseren", level: 4, type: "structure", question: "De stof HOOC—CH₂—CH₂—COOH heeft twee carbonzuurgroepen. Verklaar waarom zij in water veel beter oplost dan butaan én waarom de oplosbaarheid verandert als de stof wordt gedeprotoneerd.", modelAnswer: "De twee carbonzuurgroepen zijn polair, kunnen waterstofbruggen vormen en hebben een polaire C=O en O–H. Butaan is apolair en heeft alleen vanderwaalsinteracties met water. Na deprotonering ontstaan carboxylaationen; die worden sterk gehydrateerd door ion-dipoolinteracties, waardoor de oplosbaarheid nog verder toeneemt.", structure: { formula: "HOOC—CH₂—CH₂—COOH", groups: ["twee carbonzuurgroepen"], polar: true, hBond: "both", annotation: "barnsteenzuur" } }),
  q({ id: "m9-19", module: "M9", topic: "intermoleculaire krachten", skill: "8+ vergelijken", level: 4, type: "open", question: "Twee stoffen hebben ongeveer dezelfde molmassa: propanon en propaan-1-ol. Voorspel welke een hoger kookpunt heeft en onderbouw met molecuulstructuur, niet alleen met een tabelwaarde.", modelAnswer: "Propaan-1-ol heeft het hogere kookpunt. Beide hebben vanderwaalskrachten; propanon is polair en heeft dipool-dipoolinteracties. Propaan-1-ol heeft daarnaast een O–H-groep en kan een netwerk van waterstofbruggen vormen. Het kost daarom meer energie om de moleculen uit elkaar te krijgen.", rubric: ["propaan-1-ol gekozen", "beide vanderwaals", "propanon dipool-dipool", "alcohol waterstofbruggen"] }),
  q({ id: "m9-20", module: "M9", topic: "bindingen", skill: "8+ microniveau", level: 4, type: "mixed", question: "Leg op microniveau uit waarom natriumchloride een hoog smeltpunt heeft, in vaste vorm geen stroom geleidt, maar opgelost in water wel. Gebruik ionrooster, ion-ionbinding, vrije bewegende ionen en hydratatie.", modelAnswer: "NaCl bestaat uit een ionrooster met sterke ion-ionbinding tussen Na⁺ en Cl⁻; voor smelten is veel energie nodig. In het vaste rooster zijn de ionen niet vrij bewegend, dus is er geen ladingstransport. Water hydrateert de ionen via ion-dipoolinteracties; de losse gehydrateerde ionen kunnen bewegen en geleiden dan stroom.", rubric: ["ionrooster en sterke aantrekking", "hoog smeltpunt gekoppeld aan energie", "vast: ionen niet bewegend", "opgelost: hydratatie en bewegende ionen"] }),
  q({ id: "m9-52", module: "M9", topic: "polariteit", skill: "BINAS 40A toepassen", level: 3, type: "mixed", question: "Gebruik BINAS tabel 40A en het H-Cl-diagram. Leg uit waarom de H-Cl-binding polair is en geef aan welk atoom δ− wordt.", modelAnswer: "Eindantwoord: in BINAS 40A zoek je de elektronegativiteit van H en Cl op. Cl heeft een hogere elektronegativiteit en trekt dus harder aan het gedeelde elektronenpaar. Het elektronenpaar ligt gemiddeld dichter bij Cl. Daarom krijgt Cl δ−, H δ+ en is de H-Cl-binding een polaire atoombinding.", steps: ["Zoek H en Cl in BINAS 40A.", "Vergelijk elektronegativiteit.", "Koppel hogere elektronegativiteit aan harder trekken.", "Noteer Hδ+ en Clδ−.", "Concludeer: polaire atoombinding."], rubric: ["BINAS 40A genoemd", "Cl trekt harder", "Cl δ− en H δ+", "polaire atoombinding geconcludeerd"], visual: { type: "diagram", component: "BondPolarityDiagram", variant: "polarCovalent", alt: "H-Cl-binding met elektronenpaar dichter bij Cl en gedeeltelijke ladingen.", caption: "Lees de verschuiving van het gedeelde elektronenpaar en onderbouw die met elektronegativiteit.", purpose: "read-data" } }),
  q({ id: "m9-53", module: "M9", topic: "polariteit", skill: "bindings- en molecuulpolariteit", level: 4, type: "mixed", question: "Gebruik het molecuulpolariteitsdiagram. Waarom kan CO₂ apolair zijn terwijl H₂O polair is, ook al bevatten beide polaire bindingen?", modelAnswer: "Eindantwoord: in beide moleculen trekken O-atomen sterker aan de bindende elektronen, dus de O-bindingen zijn polair. Bij CO₂ is de vorm lineair en symmetrisch, waardoor de twee bindingsdipolen even groot en tegengesteld zijn en elkaar opheffen. Bij H₂O is de vorm gebogen, waardoor de O-H-dipolen niet tegengesteld zijn en optellen tot een resulterende dipool. Daarom is CO₂ apolair en H₂O polair.", rubric: ["polaire bindingen door O genoemd", "CO₂ lineair/symmetrisch", "dipolen heffen op bij CO₂", "H₂O gebogen en dipolen tellen op"], visual: { type: "diagram", component: "BondPolarityDiagram", variant: "moleculePolarity", alt: "CO2 met opheffende dipolen en H2O met optellende dipolen.", caption: "Eerst bindingsdipolen, daarna molecuulvorm: zo beslis je of het hele molecuul polair is.", purpose: "interpret-structure" } }),
];

const m7: Question[] = [
  q({ id: "m7-01", module: "M7", topic: "oxidator/reductor", skill: "begrip", level: 1, type: "mcq", question: "Welke uitspraak is juist?", options: ["Een oxidator staat elektronen af.", "Een reductor neemt elektronen op.", "Een oxidator neemt elektronen op.", "Elektronen rechts betekenen opname."], correctAnswer: "Een oxidator neemt elektronen op.", modelAnswer: "De oxidator neemt elektronen op en wordt gereduceerd. De reductor staat elektronen af en wordt geoxideerd." }),
  q({ id: "m7-02", module: "M7", topic: "halfreacties", skill: "herkennen", level: 1, type: "mcq", question: "Welke halfreactie beschrijft reductie?", options: ["Fe²⁺ → Fe³⁺ + e⁻", "Cl₂ + 2 e⁻ → 2 Cl⁻", "Zn → Zn²⁺ + 2 e⁻", "2 I⁻ → I₂ + 2 e⁻"], correctAnswer: "Cl₂ + 2 e⁻ → 2 Cl⁻", modelAnswer: "Elektronen links betekenen opname: reductie." }),
  q({ id: "m7-03", module: "M7", topic: "redox", skill: "begrip", level: 1, type: "open", question: "Noem de oxidator en reductor in Zn + Cu²⁺ → Zn²⁺ + Cu.", modelAnswer: "Zn is de reductor: Zn staat elektronen af en wordt Zn²⁺. Cu²⁺ is de oxidator: Cu²⁺ neemt elektronen op en wordt Cu." }),
  q({ id: "m7-04", module: "M7", topic: "Daniellcel", skill: "begrip", level: 1, type: "mcq", question: "In een Daniellcel met Zn/Zn²⁺ en Cu²⁺/Cu: van welke elektrode naar welke elektrode lopen elektronen door de draad?", options: ["van Cu naar Zn", "van Zn naar Cu", "door de zoutbrug van Zn naar Cu", "elektronen bewegen niet"], correctAnswer: "van Zn naar Cu", modelAnswer: "Zink wordt geoxideerd en levert elektronen; Cu²⁺ neemt ze op." }),
  q({ id: "m7-05", module: "M7", topic: "halfreacties", skill: "stappen", level: 2, type: "steps", question: "Stel de oxidatiehalfreactie op van aluminium naar Al³⁺.", modelAnswer: "Al(s) → Al³⁺(aq) + 3 e⁻. Atomen en lading zijn beide in balans: links lading 0, rechts +3 en −3 samen 0.", steps: ["Schrijf Al → Al³⁺.", "Breng de lading in balans met 3 e⁻ rechts.", "Controleer dat elektronen rechts staan bij afstaan."] }),
  q({ id: "m7-06", module: "M7", topic: "totaalreacties", skill: "toepassen", level: 2, type: "calculation", question: "Combineer de halfreacties Mg → Mg²⁺ + 2 e⁻ en Ag⁺ + e⁻ → Ag tot een totaalreactie.", modelAnswer: "Vermenigvuldig de zilverhalfreactie met 2: 2 Ag⁺ + 2 e⁻ → 2 Ag. Tel op: Mg + 2 Ag⁺ → Mg²⁺ + 2 Ag.", steps: ["Maak het aantal elektronen gelijk.", "Tel beide halfreacties op.", "Streep elektronen weg."] }),
  q({ id: "m7-07", module: "M7", topic: "oxidator/reductor", skill: "toepassen", level: 2, type: "open", question: "In 2 Fe²⁺ + Cl₂ → 2 Fe³⁺ + 2 Cl⁻: welke deeltjes zijn oxidator en reductor? Onderbouw met elektronen.", modelAnswer: "Fe²⁺ is de reductor: Fe²⁺ → Fe³⁺ + e⁻, dus het staat elektronen af. Cl₂ is de oxidator: Cl₂ + 2 e⁻ → 2 Cl⁻, dus het neemt elektronen op." }),
  q({ id: "m7-08", module: "M7", topic: "elektrochemische cel", skill: "toepassen", level: 2, type: "mixed", question: "Waarom is in de Daniellcel de zinkelektrode negatief en de koperelektrode positief?", modelAnswer: "Aan de zinkelektrode ontstaan door oxidatie elektronen: Zn → Zn²⁺ + 2 e⁻. Daardoor is die elektrode de elektronenbron en negatief. Aan de koperelektrode worden elektronen verbruikt door Cu²⁺; die elektrode is positief ten opzichte van zink." }),
  q({ id: "m7-09", module: "M7", topic: "Daniellcel", skill: "toetsuitleg", level: 3, type: "open", question: "Leg uit wat de zoutbrug doet in een Daniellcel. Betrek elektrische neutraliteit en ionmigratie in je antwoord.", modelAnswer: "Bij de zinkelektrode ontstaan Zn²⁺-ionen, waardoor die oplossing positiever wordt. Bij de koperelektrode verdwijnen Cu²⁺-ionen, waardoor relatief negatieve lading overblijft. Ionen uit de zoutbrug migreren om beide oplossingen elektrisch neutraal te houden; zonder die ionmigratie stopt de cel snel." }),
  q({ id: "m7-10", module: "M7", topic: "halfreacties", skill: "toetsniveau", level: 3, type: "steps", question: "Stel in zuur milieu de reductiehalfreactie op van MnO₄⁻ naar Mn²⁺.", modelAnswer: "MnO₄⁻ + 8 H⁺ + 5 e⁻ → Mn²⁺ + 4 H₂O. Eerst balanceer je O met H₂O, H met H⁺, en daarna de lading met e⁻ links.", steps: ["MnO₄⁻ → Mn²⁺", "4 H₂O rechts voor O", "8 H⁺ links voor H", "5 e⁻ links voor lading"] }),
  q({ id: "m7-11", module: "M7", topic: "totaalreacties", skill: "toetsniveau", level: 3, type: "mixed", question: "Combineer MnO₄⁻ + 8 H⁺ + 5 e⁻ → Mn²⁺ + 4 H₂O met Fe²⁺ → Fe³⁺ + e⁻.", modelAnswer: "Vermenigvuldig Fe²⁺ → Fe³⁺ + e⁻ met 5. De totaalreactie is: MnO₄⁻ + 8 H⁺ + 5 Fe²⁺ → Mn²⁺ + 4 H₂O + 5 Fe³⁺. De elektronen vallen weg." }),
  q({ id: "m7-12", module: "M7", topic: "celspanning", skill: "redeneren", level: 3, type: "open", question: "In een galvanische cel neemt de massa van één elektrode af. Welke proces vindt daar plaats en wat zegt dit over die elektrode?", modelAnswer: "Er vindt oxidatie plaats: metaalatomen verlaten de elektrode als ionen en staan elektronen af. Die elektrode is de anode en in een galvanische cel de negatieve elektrode." }),
  q({ id: "m7-13", module: "M7", topic: "redox", skill: "8+ combineren", level: 4, type: "mixed", question: "Een ijzeren spijker wordt in CuSO₄-oplossing gelegd en krijgt een koperkleurige laag. Leg de waarneming uit met een totaalreactie, oxidator/reductor en deeltjesniveau.", modelAnswer: "Fe(s) + Cu²⁺(aq) → Fe²⁺(aq) + Cu(s). Fe is de reductor en staat elektronen af; ijzeratomen gaan als Fe²⁺ in oplossing. Cu²⁺ is de oxidator, neemt elektronen op en wordt als Cu-metaal op de spijker afgezet. Daarom ontstaat een koperkleurige laag." }),
  q({ id: "m7-14", module: "M7", topic: "celdiagram", skill: "8+ notatie", level: 4, type: "open", question: "Schrijf het globale celdiagram van een Daniellcel en leg uit waarom Zn links staat.", modelAnswer: "Zn(s) | Zn²⁺(aq) || Cu²⁺(aq) | Cu(s). Links noteer je de anode, waar oxidatie plaatsvindt. Zink staat elektronen af en is daarom de anode; koper is de kathode waar reductie plaatsvindt." }),
  q({ id: "m7-15", module: "M7", topic: "elektrochemische cel", skill: "8+ redeneren", level: 4, type: "open", question: "Waarom stopt een Daniellcel uiteindelijk, ook als de draad en zoutbrug intact blijven? Noem twee chemische oorzaken.", modelAnswer: "De cel stopt wanneer een reagens uitgeput raakt, bijvoorbeeld als Cu²⁺ grotendeels is gereduceerd of het zinkmetaal is opgebruikt. Ook veranderen concentraties: de drijvende kracht van de redoxreactie en daarmee de celspanning neemt af. De zoutbrug houdt alleen ladingsevenwicht in stand; hij levert geen oneindige reagentia." }),
  q({ id: "m7-16", module: "M7", topic: "redox", skill: "BINAS 48 toepassen", level: 3, type: "mixed", question: "Je vergelijkt twee mogelijke halfreacties in BINAS 48. Leg uit hoe je bepaalt welke stof oxidator is en waarom je tabelreacties niet gedachteloos mag omdraaien.", modelAnswer: "Eindantwoord: BINAS 48 geeft standaardelektrodepotentialen bij reductiehalfreacties. De oxidator is de stof die elektronen opneemt en dus als deeltjesvorm links in een reductiehalfreactie staat. Als een halfreactie in jouw totaalreactie juist als oxidatie verloopt, draai je de halfreactie om en komen elektronen aan de andere kant te staan. Je verandert dan niet zomaar de tabelnotatie zonder te benoemen dat je hem als oxidatie gebruikt.", steps: ["Lees BINAS 48 als reductietabel.", "Zoek welk deeltje elektronen kan opnemen.", "Bepaal welke halfreactie in jouw reactie omgedraaid moet worden.", "Controleer dat elektronen in de totaalreactie wegvallen."], rubric: ["BINAS 48 als reductietabel genoemd", "oxidator neemt elektronen op", "omdraaien als oxidatie uitgelegd", "elektronencontrole genoemd"], commonMistakes: ["Een tabelwaarde of halfreactie omdraaien zonder te zeggen dat het oxidatie wordt."] }),
  q({ id: "m7-17", module: "M7", topic: "Daniellcel", skill: "figuur naar elektronenroute", level: 3, type: "open", question: "In een Daniellcel zie je Zn/Zn²⁺ links en Cu²⁺/Cu rechts. Beschrijf de elektronenroute en leg uit wat de zoutbrug wel en niet doet.", modelAnswer: "Eindantwoord: zink wordt geoxideerd aan de anode: Zn → Zn²⁺ + 2 e⁻. De elektronen lopen via de externe draad naar de koperelektrode, waar Cu²⁺ elektronen opneemt en Cu vormt. De zoutbrug laat ionen bewegen om ladingsevenwicht in de oplossingen te houden. Elektronen lopen niet door de zoutbrug.", rubric: ["Zn oxidatie/anode", "elektronen via draad naar Cu", "Cu²⁺ reductie", "zoutbrug voor ionenbalans", "niet elektronen door zoutbrug"] }),
];

const m8: Question[] = [
  q({ id: "m8-01", module: "M8", topic: "isotopen", skill: "begrip", level: 1, type: "mcq", question: "Wat is bij isotopen van hetzelfde element gelijk?", options: ["aantal neutronen", "aantal protonen", "massagetal", "relatieve massa"], correctAnswer: "aantal protonen", modelAnswer: "Isotopen hebben hetzelfde atoomnummer, dus hetzelfde aantal protonen, maar een verschillend aantal neutronen." }),
  q({ id: "m8-02", module: "M8", topic: "massaspectrometrie", skill: "begrip", level: 1, type: "mcq", question: "Wat betekent de basispiek in een massaspectrum?", options: ["de piek met hoogste m/z", "het molecuulion", "de piek met relatieve intensiteit 100%", "altijd de M+1-piek"], correctAnswer: "de piek met relatieve intensiteit 100%", modelAnswer: "De basispiek is de hoogste piek; andere pieken worden relatief daaraan weergegeven." }),
  q({ id: "m8-03", module: "M8", topic: "massaspectrometrie", skill: "begrip", level: 1, type: "open", question: "Wat is de M-piek en wat is meestal de oorzaak van een M+1-piek?", modelAnswer: "De M-piek hoort bij het molecuulion: het gehele molecuul dat is geïoniseerd. De M+1-piek komt vaak doordat één ¹²C-atoom is vervangen door ¹³C." }),
  q({ id: "m8-04", module: "M8", topic: "GC-MS", skill: "begrip", level: 1, type: "mcq", question: "Wat doet GC in GC-MS primair?", options: ["moleculen wegen", "bestanddelen van een mengsel scheiden", "IR-straling absorberen", "protonen tellen"], correctAnswer: "bestanddelen van een mengsel scheiden", modelAnswer: "Gaschromatografie scheidt stoffen op basis van hun interactie met kolom en mobiele fase; daarna kan MS per fractie identificeren." }),
  q({ id: "m8-05", module: "M8", topic: "atoommodel", skill: "begrip", level: 2, type: "open", question: "Een atoom heeft atoomnummer 17 en massagetal 37. Hoeveel protonen, neutronen en elektronen heeft een neutraal atoom?", modelAnswer: "17 protonen, 20 neutronen (37 − 17) en 17 elektronen, omdat het atoom neutraal is." }),
  q({ id: "m8-06", module: "M8", topic: "isotopen", skill: "toepassen", level: 2, type: "mixed", question: "Waarom geeft een verbinding met één Cl-atoom vaak een M- en M+2-piek in ongeveer 3 : 1-verhouding?", modelAnswer: "Chloor komt vooral voor als ³⁵Cl en voor ongeveer een derde als ³⁷Cl. Moleculen met ³⁷Cl zijn 2 u zwaarder dan dezelfde moleculen met ³⁵Cl. De natuurlijke verhouding leidt tot een M : M+2-intensiteit van ongeveer 3 : 1." }),
  q({ id: "m8-07", module: "M8", topic: "massaspectrometrie", skill: "toepassen", level: 2, type: "mcq", question: "Een piek bij m/z 43 is niet de M-piek maar wel de hoogste piek. Hoe noem je die het best?", options: ["basispiek en mogelijk fragmentpiek", "M+2-piek", "isotooppiek van het hele molecuul", "retentietijd"], correctAnswer: "basispiek en mogelijk fragmentpiek", modelAnswer: "De basispiek is op intensiteit gebaseerd. Als deze niet het hele molecuul is, betreft het een fragmention." }),
  q({ id: "m8-08", module: "M8", topic: "GC-MS", skill: "toepassen", level: 2, type: "open", question: "Waarom is GC-MS sterker voor een mengsel dan alleen een massaspectrum van het hele mengsel?", modelAnswer: "GC scheidt de componenten in de tijd. Daardoor krijgt de MS afzonderlijke spectra van stoffen op verschillende retentietijden in plaats van één overlappend mengselspectrum. Dat maakt identificatie betrouwbaarder." }),
  q({ id: "m8-09", module: "M8", topic: "massaspectrometrie", skill: "toetsniveau", level: 3, type: "open", question: "Een stof heeft M = 86 en een duidelijke M+1-piek van ongeveer 6,6% van M. Schat het aantal C-atomen en leg je schatting uit.", modelAnswer: "De natuurlijke abundantie van ¹³C is ongeveer 1,1% per C-atoom. Een M+1-piek van 6,6% past dus bij ongeveer 6 C-atomen (6 × 1,1%). Dit is een schatting; andere isotopen kunnen kleine bijdragen leveren." }),
  q({ id: "m8-10", module: "M8", topic: "fragmentatie", skill: "toetsniveau", level: 3, type: "mixed", question: "Waarom kunnen fragmentpieken juist nuttig zijn voor structuurherkenning, hoewel het molecuulion uiteengevallen is?", modelAnswer: "Fragmentatie verloopt niet willekeurig: zwakkere bindingen en stabiele ionen worden relatief gemakkelijk gevormd. Kenmerkende fragmentmassa’s geven daarom aanwijzingen voor substructuren of functionele groepen. Je combineert die aanwijzingen met de M-piek en eventueel IR/NMR." }),
  q({ id: "m8-11", module: "M8", topic: "analysetechnieken", skill: "vergelijken", level: 3, type: "open", question: "Welke globale informatie levert IR die GC-MS niet direct levert, en welke informatie levert NMR aanvullend?", modelAnswer: "IR laat karakteristieke trillingen zien en is daarom bruikbaar voor functionele groepen, bijvoorbeeld een C=O-band. NMR geeft informatie over de chemische omgeving van kernen, vaak ¹H of ¹³C, en helpt met het aantal verschillende omgevingen en buren. GC-MS geeft vooral scheiding, massa en fragmentatie." }),
  q({ id: "m8-12", module: "M8", topic: "isotopen", skill: "toetsniveau", level: 3, type: "calculation", question: "Boor bestaat uit 19,9% ¹⁰B en 80,1% ¹¹B. Bereken de gemiddelde atoommassa met hele massagetallen.", correctAnswer: "10,801 u", modelAnswer: "Gemiddelde massa = 0,199 × 10 + 0,801 × 11 = 10,801 u. Een periodieke-tabelwaarde kan licht afwijken doordat echte isotopenmassa’s niet exact hele getallen zijn." }),
  q({ id: "m8-13", module: "M8", topic: "GC-MS", skill: "8+ combineren", level: 4, type: "mixed", question: "In een GC-MS-chromatogram zitten twee pieken op 2,1 en 4,8 min. De tweede piek heeft een massaspectrum met M en M+2 in 1 : 1-verhouding. Welke conclusie is sterk verdedigbaar en welke niet?", modelAnswer: "Sterk verdedigbaar: de tweede component bevat waarschijnlijk één Br-atoom, omdat ⁷⁹Br en ⁸¹Br ongeveer even abundant zijn en 2 u verschillen. Ook heeft die component retentietijd 4,8 min onder deze omstandigheden. Niet verdedigbaar zonder extra data: de exacte volledige structuur of dat de tweede component ‘zwaarder’ is alleen op basis van retentietijd." }),
  q({ id: "m8-14", module: "M8", topic: "atoommodel", skill: "8+ verklaren", level: 4, type: "open", question: "Vergelijk Thomsons en Rutherfords atoommodel. Welke experimentele waarneming maakte het model van Rutherford noodzakelijk?", modelAnswer: "Thomson stelde een diffuse positieve massa voor met elektronen erin. Bij Rutherfords goudfolie-experiment gingen de meeste alfadeeltjes rechtdoor, maar een klein deel werd sterk afgebogen of teruggekaatst. Dat kan alleen als positieve lading en vrijwel alle massa geconcentreerd zijn in een kleine, dichte kern en het atoom grotendeels leeg is." }),
  q({ id: "m8-15", module: "M8", topic: "analysetechnieken", skill: "8+ strategie", level: 4, type: "open", question: "Je hebt een onbekende vluchtige organische stof. Beschrijf een verdedigbare analysevolgorde met GC-MS, IR en NMR en leg uit wat elke techniek toevoegt.", modelAnswer: "Ik begin met GC-MS om te zien of het monster één component is en om retentietijd, molecuulmassa, isotopenpatronen en fragmenten te krijgen. Daarna gebruik ik IR om functionele groepen te bevestigen of uit te sluiten. Ten slotte gebruik ik NMR voor het aantal en type H- of C-omgevingen en koppelingen. De technieken leveren complementair bewijs voor één structuur." }),
  q({ id: "m8-16", module: "M8", topic: "atoommodellen", skill: "Thomson vs Rutherford", level: 1, type: "mcq", question: "Welke uitspraak vergelijkt Thomson en Rutherford correct?", options: ["Thomson tekent een kleine positieve kern; Rutherford tekent positieve massa verspreid door het atoom.", "Thomson tekent positieve massa verspreid met elektronen erin; Rutherford tekent een kleine positieve kern met elektronen daarbuiten.", "Beide modellen hebben vaste elektronenschillen zoals het Bohrmodel.", "Rutherford tekent geen elektronen buiten de kern."], correctAnswer: "Thomson tekent positieve massa verspreid met elektronen erin; Rutherford tekent een kleine positieve kern met elektronen daarbuiten.", modelAnswer: "Eindantwoord: Thomson heeft positieve massa verspreid door het atoom met elektronen erin. Rutherford heeft een kleine positieve kern, vrijwel alle massa in die kern en elektronen buiten de kern.", rubric: ["Thomson: positief verspreid", "Rutherford: kleine positieve kern", "elektronen buiten de kern genoemd"], commonMistakes: ["Rutherford verwarren met een volledig Bohr-schillenmodel."] }),
  q({ id: "m8-17", module: "M8", topic: "atoommodellen", skill: "goudfolie interpreteren", level: 2, type: "mixed", question: "Gebruik het goudfolie-schema. Welke waarneming maakte het Thomson-model onvoldoende, en welke conclusie trok Rutherford?", modelAnswer: "Eindantwoord: de meeste alfadeeltjes gingen rechtdoor, maar een klein deel werd sterk afgebogen of teruggekaatst. Dat past niet goed bij Thomson, omdat positieve lading daar verspreid is. Rutherford concludeerde dat positieve lading en bijna alle massa geconcentreerd zijn in een kleine kern en dat het atoom grotendeels lege ruimte is.", steps: ["Lees eerst de pijlen in het schema.", "Noem de twee waarnemingen.", "Leg uit waarom verspreide positieve lading sterke afbuiging niet goed verklaart.", "Concludeer: kleine positieve kern en veel lege ruimte."], rubric: ["meeste alfadeeltjes rechtdoor", "klein deel sterk afgebogen/teruggekaatst", "kleine positieve kern", "atoom grotendeels lege ruimte"], visual: { type: "diagram", component: "RutherfordScatteringDiagram", alt: "Goudfolie-schema met alfadeeltjes die meestal rechtdoor gaan, enkele afbuigen en heel weinig sterk terugkaatsen.", caption: "Gebruik de richting van de alfadeeltjes als waarneming en trek daarna pas je conclusie.", purpose: "read-data" } }),
  q({ id: "m8-18", module: "M8", topic: "atoommodel tekenen", skill: "Rutherford tekenen", level: 2, type: "open", question: "Beschrijf hoe je op een toets een Rutherfordmodel tekent. Noem wat je labelt en wat je juist niet als vaste schillen hoeft te tekenen.", modelAnswer: "Eindantwoord: teken een kleine positieve kern in het midden, zet elektronen buiten de kern en laat veel lege ruimte zien. Label de kern, positieve kern/protonen als dat gevraagd is, elektronen en lege ruimte. Vaste elektronenschillen horen niet noodzakelijk bij het Rutherfordmodel; dat is de extra stap van het Bohr- of schillenmodel.", steps: ["Kern klein in het midden.", "Elektronen buiten de kern.", "Veel lege ruimte zichtbaar maken.", "Labels toevoegen die de vraag vraagt.", "Niet automatisch volledige schillen tekenen."], rubric: ["kleine positieve kern", "elektronen buiten de kern", "veel lege ruimte", "Rutherford niet als volledig schillenmodel behandeld"] }),
  q({ id: "m8-19", module: "M8", topic: "atoommodel tekenen", skill: "Bohr/schillenmodel", level: 2, type: "open", question: "Teken in woorden het Bohr/schillenmodel van een neutraal koolstofatoom met atoomnummer 6. Wat moet in de kern en hoe verdeel je de elektronen?", modelAnswer: "Eindantwoord: koolstof heeft 6 protonen in de kern en als neutraal atoom 6 elektronen. In een eenvoudig schillenmodel zet je 2 elektronen in de eerste schil en 4 in de tweede schil. Neutronen zet je alleen met een gegeven massagetal; zonder massagetal kun je hun aantal niet bepalen.", steps: ["Atoomnummer 6 betekent 6 protonen.", "Neutraal betekent 6 elektronen.", "Vul eerst de eerste schil met 2 elektronen.", "Zet de overige 4 elektronen in de tweede schil.", "Noem neutronen alleen als massagetal gegeven is."], rubric: ["6 protonen", "6 elektronen", "2 en 4 over de schillen", "neutronen niet gegokt"] }),
  q({ id: "m8-20", module: "M8", topic: "isotopen en atoommodel", skill: "isotoop tekenen", level: 2, type: "open", question: "Vergelijk een tekening van ¹²C en ¹⁴C. Welke deeltjes blijven gelijk en welke veranderen?", modelAnswer: "Eindantwoord: beide isotopen zijn koolstof en hebben dus 6 protonen. Bij neutrale atomen hebben ze ook allebei 6 elektronen. Het verschil zit in de neutronen: ¹²C heeft 12 − 6 = 6 neutronen en ¹⁴C heeft 14 − 6 = 8 neutronen.", steps: ["Zelfde element betekent zelfde aantal protonen.", "Koolstof heeft atoomnummer 6.", "Neutronen = massagetal - protonen.", "Neutrale isotopen hebben hetzelfde aantal elektronen als protonen."], rubric: ["zelfde protonen", "ander aantal neutronen", "elektronen gelijk bij neutraal", "correcte aantallen 6 en 8 neutronen"] }),
  q({ id: "m8-21", module: "M8", topic: "ionen en atoommodel", skill: "ion tekenen", level: 2, type: "open", question: "Een magnesiumatoom heeft atoomnummer 12. Beschrijf wat verandert wanneer je Mg²⁺ tekent in plaats van neutraal Mg.", modelAnswer: "Eindantwoord: de kern verandert niet: magnesium heeft nog steeds 12 protonen. Een neutraal Mg-atoom heeft 12 elektronen, maar Mg²⁺ heeft twee elektronen afgestaan en heeft dus 10 elektronen. De positieve lading ontstaat doordat er 12 protonen en 10 elektronen zijn.", steps: ["Atoomnummer blijft 12 protonen.", "Neutraal Mg heeft 12 elektronen.", "Mg²⁺ betekent twee elektronen minder.", "Controleer: 12+ en 10− geeft netto 2+."], rubric: ["kern/protonen blijven gelijk", "twee elektronen eraf", "10 elektronen", "lading 2+ gecontroleerd"] }),
  q({ id: "m8-22", module: "M8", topic: "atoommodellen", skill: "Rutherford vs Bohr", level: 3, type: "mcq", question: "Waarom is het Rutherfordmodel niet hetzelfde als een volledig Bohr/schillenmodel?", options: ["Rutherford bewijst vooral een kleine positieve kern en veel lege ruimte; Bohr voegt vaste elektronenschillen toe.", "Rutherford heeft geen kern, Bohr wel.", "Bohr laat alleen neutronen zien en Rutherford alleen protonen.", "Rutherford en Bohr verschillen alleen in de kleur van de elektronen."], correctAnswer: "Rutherford bewijst vooral een kleine positieve kern en veel lege ruimte; Bohr voegt vaste elektronenschillen toe.", modelAnswer: "Eindantwoord: Rutherford verklaart uit het goudfolie-experiment vooral de kleine positieve kern en de lege ruimte. Het Bohr- of schillenmodel voegt vaste elektronenbanen of schillen toe.", rubric: ["Rutherford: kern en lege ruimte", "Bohr: schillen", "verschil niet oppervlakkig beschreven"] }),
  q({ id: "m8-23", module: "M8", topic: "atoommodel tekenen", skill: "tekenvolgorde", level: 3, type: "order", question: "Zet de stappen voor een toetswaardige atoommodeltekening in de juiste volgorde.", options: ["Controleer lading en atoomnummer.", "Teken de kern in het midden.", "Zet protonen en neutronen in de kern als dat gevraagd wordt.", "Zet elektronen buiten de kern of op schillen.", "Label wat de vraag vraagt."], correctAnswer: "Teken de kern in het midden. > Zet protonen en neutronen in de kern als dat gevraagd wordt. > Zet elektronen buiten de kern of op schillen. > Label wat de vraag vraagt. > Controleer lading en atoomnummer.", modelAnswer: "Eindantwoord: begin met de kern, vul gevraagde kerndeeltjes in, plaats daarna elektronen buiten de kern of op schillen, label de gevraagde onderdelen en controleer als laatste atoomnummer en lading.", steps: ["kern", "protonen/neutronen", "elektronen/schillen", "labels", "controle"] }),
  q({ id: "m8-24", module: "M8", topic: "atoommodellen", skill: "waarneming koppelen", level: 3, type: "mixed", question: "Welke waarneming past beter bij Rutherfords model dan bij Thomsons model: bijna alle alfadeeltjes rechtdoor, of sommige alfadeeltjes sterk teruggekaatst? Leg uit waarom beide waarnemingen samen nodig zijn.", modelAnswer: "Eindantwoord: vooral de sterke terugkaatsing past beter bij Rutherford dan bij Thomson, omdat daarvoor een klein geconcentreerd positief gebied nodig is. De waarneming dat bijna alle deeltjes rechtdoor gaan is ook nodig, want die laat zien dat het atoom grotendeels lege ruimte is. Samen geven ze het kernmodel.", rubric: ["sterke terugkaatsing aan kern gekoppeld", "rechtdoor aan lege ruimte gekoppeld", "samen kernmodel geconcludeerd"] }),
  q({ id: "m8-25", module: "M8", topic: "atoommodel tekenen", skill: "tekencheck toepassen", level: 3, type: "mixed", question: "Gebruik de tekenhulp. Een leerling tekent O²⁻ met 8 protonen, 8 neutronen en 8 elektronen. Welke controle uit de tekenhulp laat zien dat dit ion niet klopt?", modelAnswer: "Eindantwoord: de ladingcontrole laat zien dat dit niet klopt. Zuurstof heeft inderdaad 8 protonen, maar O²⁻ moet twee elektronen extra hebben: 10 elektronen. Met 8 protonen en 8 elektronen is de lading neutraal, niet 2−.", steps: ["Controleer eerst protonen: zuurstof heeft 8.", "Lees de lading O²⁻ als twee elektronen extra.", "Vergelijk protonen en elektronen.", "8 p+ en 8 e− is neutraal; voor 2− zijn 10 e− nodig."], rubric: ["ladingcontrole gebruikt", "O²⁻ heeft 10 elektronen", "8 elektronen zou neutraal zijn"], visual: { type: "diagram", component: "AtomicModelsDiagram", variant: "drawingGuide", alt: "Tekenhulp voor kern, protonen en neutronen, elektronen en ladingcontrole.", caption: "Controleer na het tekenen altijd of protonen en elektronen de gevraagde lading geven.", purpose: "explanation-only" } }),
  q({ id: "m8-26", module: "M8", topic: "atoommodellen", skill: "Rutherforddiagram uitleggen", level: 3, type: "mixed", question: "Gebruik het Rutherforddiagram. Leg uit waarom de combinatie van 'meeste rechtdoor' en 'heel weinig sterk terug' sterker bewijs geeft dan één waarneming apart.", modelAnswer: "Eindantwoord: dat de meeste alfadeeltjes rechtdoor gaan laat zien dat het atoom grotendeels lege ruimte is. Dat heel weinig deeltjes sterk terugkaatsen laat zien dat er toch een klein, geconcentreerd en positief gebied is dat de positieve alfadeeltjes sterk afstoot. Samen verklaren deze waarnemingen het kernmodel: kleine positieve kern met bijna alle massa en veel lege ruimte daarbuiten.", steps: ["Noem eerst de twee waarnemingen.", "Koppel rechtdoor aan lege ruimte.", "Koppel sterke terugkaatsing aan kleine positieve kern.", "Sluit af met het kernmodel."], rubric: ["meeste rechtdoor aan lege ruimte gekoppeld", "sterk terug aan kleine positieve kern gekoppeld", "positieve lading/massa in kern", "samen kernmodel geconcludeerd"], visual: { type: "diagram", component: "RutherfordScatteringDiagram", alt: "Rutherforddiagram met alfadeeltjes door dun goudfolie.", caption: "Trek uit elke pijlsoort een aparte conclusie en combineer die pas daarna.", purpose: "read-data" } }),
  q({ id: "m8-27", module: "M8", topic: "GC-MS", skill: "chromatogram en spectrum combineren", level: 4, type: "mixed", question: "Een chromatogram toont twee duidelijke GC-pieken. Van de tweede piek geeft het massaspectrum een M- en M+2-piek in ongeveer 3 : 1-verhouding. Welke conclusie mag je wel trekken, en welke nog niet?", modelAnswer: "Eindantwoord: twee GC-pieken wijzen op twee onder deze omstandigheden gescheiden componenten. Het M/M+2-patroon van ongeveer 3 : 1 bij de tweede component past bij één chlooratoom in die component. Je mag nog niet de volledige structuur vastleggen: daarvoor heb je bijvoorbeeld fragmenten, IR, NMR of een referentiestof nodig. Retentietijd alleen bewijst ook niet dat de stof zwaarder is.", rubric: ["twee componenten uit GC", "3:1 M/M+2 aan Cl gekoppeld", "volledige structuur nog niet bewezen", "retentietijd niet als molmassa gebruikt"], visual: { type: "diagram", component: "QuestionGcChromatogram", variant: "two-components", alt: "GC-chromatogram met twee componentpieken.", caption: "Gebruik GC voor scheiding; combineer daarna per piek met MS-informatie.", purpose: "read-data" } }),
];

const m5d: Question[] = [
  q({ id: "m5d-01", module: "M5D", topic: "DNA", skill: "begrip", level: 1, type: "mcq", question: "Welke set bevat alleen DNA-basen?", options: ["A, U, C, G", "A, T, C, G", "A, T, U, G", "A, C, G, P"], correctAnswer: "A, T, C, G", modelAnswer: "DNA bevat adenine, thymine, cytosine en guanine. RNA gebruikt uracil in plaats van thymine." }),
  q({ id: "m5d-02", module: "M5D", topic: "nucleotiden", skill: "begrip", level: 1, type: "open", question: "Noem de drie onderdelen van een DNA-nucleotide.", modelAnswer: "Een fosfaatgroep, de suiker desoxyribose en één stikstofbase." }),
  q({ id: "m5d-03", module: "M5D", topic: "polymeren", skill: "begrip", level: 1, type: "mcq", question: "Waarom is DNA een polymeer?", options: ["DNA bestaat uit één groot atoom.", "DNA bestaat uit veel herhalende nucleotiden.", "DNA lost altijd op in water.", "DNA bevat alleen covalente bindingen."], correctAnswer: "DNA bestaat uit veel herhalende nucleotiden.", modelAnswer: "Een polymeer bestaat uit veel herhalende bouwstenen; bij DNA zijn dat nucleotiden." }),
  q({ id: "m5d-04", module: "M5D", topic: "eiwitten", skill: "begrip", level: 1, type: "mcq", question: "Welke binding verbindt aminozuren in een eiwit?", options: ["esterbinding", "ionbinding", "peptidebinding", "waterstofbrug"], correctAnswer: "peptidebinding", modelAnswer: "Een peptidebinding is een amidebinding tussen de carboxylgroep van het ene en de aminogroep van het andere aminozuur." }),
  q({ id: "m5d-05", module: "M5D", topic: "DNA/RNA", skill: "toepassen", level: 2, type: "open", question: "Noem twee verschillen tussen DNA en RNA die je op een toets veilig kunt gebruiken.", modelAnswer: "DNA bevat desoxyribose en thymine; RNA bevat ribose en uracil. DNA is meestal dubbelstrengs, RNA meestal enkelstrengs. Twee correcte verschillen zijn voldoende, zolang je ze niet verwisselt." }),
  q({ id: "m5d-06", module: "M5D", topic: "DNA", skill: "toepassen", level: 2, type: "calculation", question: "Een DNA-streng heeft de basenvolgorde A–C–G–T–T. Geef de complementaire DNA-streng.", correctAnswer: "T–G–C–A–A", modelAnswer: "A paart met T en C paart met G. De complementaire volgorde is T–G–C–A–A." }),
  q({ id: "m5d-07", module: "M5D", topic: "polymeren", skill: "toepassen", level: 2, type: "open", question: "Leg het verschil uit tussen additiepolymerisatie en condensatiepolymerisatie.", modelAnswer: "Bij additiepolymerisatie openen meestal C=C-bindingen van monomeren en ontstaan polymeren zonder afsplitsing van kleine moleculen. Bij condensatiepolymerisatie reageren functionele groepen en splitst vaak een klein molecuul, bijvoorbeeld water, af." }),
  q({ id: "m5d-08", module: "M5D", topic: "vetten", skill: "structuur", level: 2, type: "structure", question: "In een triglyceride zijn vetzuren gekoppeld aan glycerol. Welke binding herken je tussen een carboxylgroep en een OH-groep van glycerol?", modelAnswer: "Dat is een esterbinding. Deze ontstaat door condensatie tussen een carboxylgroep en een hydroxylgroep, waarbij water wordt afgesplitst.", structure: { formula: "R—C(=O)—O—CH₂", groups: ["esterbinding", "carbonylgroep"], polar: true, hBond: "acceptor", annotation: "esterfragment" } }),
  q({ id: "m5d-09", module: "M5D", topic: "DNA", skill: "toetsuitleg", level: 3, type: "open", question: "Leg uit waarom DNA geschikt is voor opslag van erfelijke informatie. Noem zowel volgorde als complementaire basenparing.", modelAnswer: "De volgorde van de basen in DNA kan veel verschillende informatie coderen. Door complementaire basenparing (A–T en C–G) kan een streng als matrijs dienen voor een betrouwbare kopie van de andere streng. De suiker-fosfaatruggengraat houdt de nucleotiden in een stabiele polymeerketen." }),
  q({ id: "m5d-10", module: "M5D", topic: "polymeren", skill: "toetsniveau", level: 3, type: "mixed", question: "Een polyester wordt gevormd uit een dizuur en een diol. Leg uit waarom beide monomeren ten minste twee reagerende groepen nodig hebben.", modelAnswer: "Voor een lange keten moet elk ingebouwd monomeer aan twee kanten verder kunnen reageren. Het dizuur heeft twee carboxylgroepen en de diol twee hydroxylgroepen. Zo kan herhaald esterbindingvorming optreden; met een monofunctioneel monomeer zou de keten worden beëindigd." }),
  q({ id: "m5d-11", module: "M5D", topic: "eiwitten", skill: "toetsniveau", level: 3, type: "open", question: "Waarom is een peptidebinding tegelijk een amidebinding? Beschrijf welke functionele groepen reageren.", modelAnswer: "Een peptidebinding ontstaat wanneer de carboxylgroep (–COOH) van één aminozuur reageert met de aminogroep (–NH₂) van een ander aminozuur. In het product zit de groep –C(=O)–NH–; dat is per definitie een amidegroep. Daarom heet de binding peptide- én amidebinding." }),
  q({ id: "m5d-12", module: "M5D", topic: "koolhydraten", skill: "toetsniveau", level: 3, type: "open", question: "Vergelijk zetmeel en eiwit als polymeren: noem voor elk de monomeren en de soort binding in de hoofdketen.", modelAnswer: "Zetmeel is opgebouwd uit glucose-eenheden, gekoppeld via glycosidische bindingen (een type condensatieverbinding). Eiwitten zijn opgebouwd uit aminozuren, gekoppeld via peptide- of amidebindingen. Beide zijn polymeren maar hebben verschillende monomeren en koppelingen." }),
  q({ id: "m5d-13", module: "M5D", topic: "DNA/RNA", skill: "8+ combineren", level: 4, type: "mixed", question: "Een RNA-molecuul heeft 24% A, 18% U, 28% C en 30% G. Waarom mag je hieruit niet concluderen dat het molecuul dubbelstrengs DNA is?", modelAnswer: "RNA bevat U in plaats van T, dus de aanwezigheid van U sluit DNA al uit. Bovendien hoeft enkelstrengs RNA niet te voldoen aan A = U en C = G over het hele molecuul. Bij dubbelstrengs DNA zouden door complementaire paring A en T, en C en G in gelijke aantallen voorkomen." }),
  q({ id: "m5d-14", module: "M5D", topic: "polymeren", skill: "8+ redeneren", level: 4, type: "open", question: "Een polymerisatie met een difunctioneel zuur en een difunctionele amine levert een polyamide. Leg uit welk klein molecuul afsplitst en waarom de gevormde bindingen waterstofbruggen tussen ketens kunnen geven.", modelAnswer: "Bij reactie van –COOH met –NH₂ ontstaat een amidebinding en splitst water af. De amidegroep bevat een polaire C=O die waterstofbruggen kan accepteren en vaak een N–H die kan doneren. Daardoor kunnen polymeerketens onderling waterstofbruggen vormen, wat de sterkte kan verhogen." }),
  q({ id: "m5d-15", module: "M5D", topic: "enzymen", skill: "8+ uitleg", level: 4, type: "open", question: "Leg uit waarom een verandering in de aminozuurvolgorde van een enzym de werking kan veranderen, zonder te zeggen dat ‘het DNA kapot is’.", modelAnswer: "De aminozuurvolgorde bepaalt welke interacties tijdens vouwing mogelijk zijn en daarmee de driedimensionale vorm van het enzym. Een verandering kan de vorm of lading in het actieve centrum wijzigen. Het substraat past dan minder goed of de katalytische aminozuren staan niet goed gepositioneerd, waardoor de activiteit verandert." }),
];

const baseQuestions: Question[] = [
  ...m4Questions,
  ...m6Questions,
  ...m10,
  ...m10Questions,
  ...m10PriorityQuestions,
  ...m9,
  ...m9Questions,
  ...m7,
  ...m8,
  ...m8PriorityQuestions,
  ...curriculumGapQuestions,
  ...massSpecMasteryQuestions,
  ...m5d,
  ...m5dPriorityQuestions,
  ...structureQuestions,
  ...structureGraphQuestions,
  ...structureBuildQuestions,
  ...coverageQaQuestions,
  ...figureQuestions,
];

const replacementById = new Map(qualityReplacementQuestions.map((question) => [question.id, question]));
const genericM10CalculationPlan = ["Zet alle volumes om naar liter.", "Schrijf de formule en reactieverhouding op.", "Vul in met eenheden.", "Rond pas het eindantwoord passend af."];

// Oude instapitems worden op hetzelfde ID vervangen. Daarnaast krijgt iedere
// rekenvraag in M10 een zichtbaar stappenplan, ook wanneer de bronvraag dat
// oorspronkelijk niet afzonderlijk had meegekregen.
export const questions: Question[] = baseQuestions.map((question) => {
  const active = replacementById.get(question.id) ?? question;
  const needsM10Plan = active.module === "M10" && !active.steps && (active.type === "calculation" || (active.type === "mixed" && /bereken|molariteit|massapercentage/i.test(active.question)));
  return enhanceQuestion(needsM10Plan ? { ...active, steps: genericM10CalculationPlan } : active);
});

export const questionCounts = questions.reduce<Record<string, number>>((counts, question) => {
  counts[question.module] = (counts[question.module] ?? 0) + 1;
  return counts;
}, {});
